1	// Triage for the create-extractor routine (routine.md): before the agent does any
2	// work, decide how to handle an extractor-request issue. The host's situation
3	// sorts it into one of these:
4	//   "supported" — the host already has a dedicated source. We DON'T close it any
5	//                 more: the pipeline runs in **supported mode** and adds a fresh
6	//                 integration case to that existing source (hardening it against a
7	//                 second real page) instead of scaffolding a new one; resolve-
8	//                 source.js resolves which existing source via the sources' matches().
9	//   "deny"      — the host is on the fallback denylist.            } these three
10	//   "allow"     — the host is on the fallback allowlist (generic   } still CLOSE
11	//                 extractor already handles it).                    } the request
12	//   "sample"    — another OPEN extractor-request issue already targets this host
13	//                 (a request whose PR is still in review keeps its issue open).
14	//                 The lowest issue number wins; the newer request's URL is folded
15	//                 into the leader issue as an extra sample page.
16	// deny / allow / sample close the issue and skip the agent (skipAgent=true);
17	// supported and "no match" both PROCEED (skipAgent=false) — supported in supported
18	// mode, no-match in new-source mode.
19	//
20	// Reuses fallback-policy.js (the popup's host classifier) for deny/allow and
21	// resolve-source.js (the sources' matches()) for supported, so the workflow and
22	// the popup can never disagree about a host.
23	//
24	// CLI (run by the routine's agent):
25	//   in  (env):  ISSUE_BODY, ISSUE_TITLE, ISSUE_NUMBER — the issue's raw fields
26	//   in  (file): $OPEN_REQUESTS_FILE (default /tmp/open-requests.json) — the array
27	//               of OTHER open extractor-request issues ([{number,title,body}]),
28	//               which the agent gathers via the GitHub tools and writes here (the
29	//               shell has no GitHub API); this script never touches the network, so
30	//               the unit tests stay offline. Missing -> the sample check is skipped.
31	//   out (stdout): one JSON object — { skipAgent, reason, mode, url, host,
32	//                 waitSelector, slug, sourceBase, caseName, branch, sourcePath,
33	//                 casePath, duplicateOf, message }
34	// As a module (the tests): exports firstUrl(), waitSelectorOf(), runTriage().
35	"use strict";
36	
37	const fs = require("node:fs");
38	const path = require("node:path");
39	const { pathToFileURL } = require("node:url");
40	const { namesFor } = require("./extractor-naming");
41	const { resolveSourceBaseName } = require("./resolve-source");
42	
43	const OPEN_REQUESTS_PATH = process.env.OPEN_REQUESTS_FILE || "/tmp/open-requests.json";
44	
45	// Turn an issue's event URL (+ number) into every mode-aware name the routine
46	// uses, for BOTH modes. The authority on "is this host already supported" is an
47	// existing source's matches() (resolve-source, run against the committed tree):
48	//   "new"       — no source matches yet. Scaffold a brand-new source; the slug
49	//                 names the source file, the branch, AND the (single) case.
50	//   "supported" — a source already matches. Don't add a source; add a fresh
51	//                 integration case to it, keyed by the EXISTING source's file name
52	//                 + the issue number (NOT the slug — cinema.co.il is served by
53	//                 telavivcinematheque.js), so repeated requests each get a unique
54	//                 case + branch. (Run against `main`: a new-mode source exists only
55	//                 on the feature branch, so resolve-source returns "" for it there.)
56	function planNames(url, issueNumber) {
57	  const { host, slug, caseName: newCase, matchesRegex } = namesFor(url);
58	  const existingBase = slug ? resolveSourceBaseName(url) : "";
59	  const mode = existingBase ? "supported" : "new";
60	  const sourceBase = existingBase || slug;
61	  const caseName = mode === "supported" ? `${sourceBase}-${issueNumber}` : newCase;
62	  const branch = sourceBase ? `claude/extractor/${caseName}` : "";
63	  const sourcePath = sourceBase ? `extension/event-extractors/custom/${sourceBase}.js` : "";
64	  const casePath = caseName ? `dev/requirements/extractor/expected/${caseName}.json` : "";
65	  return { host, slug, mode, sourceBase, caseName, branch, sourcePath, casePath, matchesRegex };
66	}
67	
68	// The first http(s) URL in some text. The request form makes the URL field
69	// required and lists it first, so the first URL in the body is the event page.
70	function firstUrl(text) {
71	  const m = (text || "").match(/https?:\/\/[^\s<>)"'\]]+/);
72	  return m ? m[0] : "";
73	}
74	
75	// The value of a GitHub issue-form field from the rendered issue body. A form
76	// renders each answer as "### <label>\n\n<value>" up to the next "### " heading;
77	// an empty field renders the literal "_No response_". Returns the trimmed value,
78	// or "" when the section is missing or empty.
79	function fieldValue(body, label) {
80	  const lines = String(body || "").split(/\r?\n/);
81	  const i = lines.findIndex((l) => l.trim() === `### ${label}`);
82	  if (i < 0) return "";
83	  const out = [];
84	  for (let j = i + 1; j < lines.length; j++) {
85	    if (/^### /.test(lines[j])) break;
86	    out.push(lines[j]);
87	  }
88	  const val = out.join("\n").trim();
89	  return val === "_No response_" ? "" : val;
90	}
91	
92	// The CSS selector the extension derived from the live page (the form's
93	// "Wait-for selector" field, #603), handed to ScraperAPI as wait_for_selector when
94	// the pipeline re-records the page. A selector is one line; take only the first,
95	// strip an accidental surrounding code span, and bound the length so a pasted
96	// paragraph or a hostile issue body can't feed a giant value into the fetch URL
97	// (the fetch-page workflow url-encodes it regardless).
98	function waitSelectorOf(body) {
99	  const first = fieldValue(body, "Wait-for selector").split(/\r?\n/)[0].trim();
100	  return first.replace(/^`+|`+$/g, "").trim().slice(0, 200);
101	}
102	
103	// The www-stripped host of the first URL in an issue's body (or title), or ""
104	// when there's no parseable URL.
105	function hostOf({ body = "", title = "" } = {}) {
106	  try {
107	    return new URL(firstUrl(body) || firstUrl(title)).hostname.replace(/^www\./, "");
108	  } catch (e) {
109	    return "";
110	  }
111	}
112	
113	// The lowest-numbered OPEN request that targets `host`, other than the current
114	// issue. Returns its number, or null when there's no in-flight duplicate. The
115	// caller decides whether the CURRENT issue defers to it: it does unless the
116	// current issue is itself the lowest (the elder always proceeds, so exactly one
117	// of a set of same-host requests runs the agent).
118	function earlierDuplicate(host, currentNumber, openRequests) {
119	  // Without the current number we can't tell whether we're the elder, so fail
120	  // open (don't dedupe) rather than risk closing the wrong one.
121	  if (!host || !Number.isInteger(currentNumber) || !Array.isArray(openRequests)) return null;
122	  const sameHost = openRequests
123	    .filter((r) => r && Number(r.number) !== currentNumber && hostOf(r) === host)
124	    .map((r) => Number(r.number))
125	    .filter((n) => Number.isInteger(n));
126	  if (!sameHost.length) return null;
127	  const lowest = Math.min(...sameHost);
128	  // The current issue defers only when an EARLIER (lower-numbered) request
129	  // exists. If every same-host peer is newer, the current issue is the elder
130	  // and proceeds — those peers will defer to it when their own triage runs.
131	  return currentNumber < lowest ? null : lowest;
132	}
133	
134	function skipMessage(reason, { host, duplicateOf }) {
135	  switch (reason) {
136	    case "deny":
137	      return (
138	        `This request was auto-triaged and closed without an agent run: \`${host}\` is on the ` +
139	        `fallback **denylist** — we deliberately don't extract events there, so a custom source ` +
140	        `won't be added.\n\n` +
141	        `See the host classifier in \`extension/config.js\`. ` +
142	        `If you think this is wrong, comment and a maintainer can revisit.`
143	      );
