1	import { copyFileSync, mkdirSync, rmSync, readFileSync, writeFileSync, existsSync, realpathSync } from 'node:fs';
2	import { execFileSync } from 'node:child_process';
3	import { join, dirname } from 'node:path';
4	import { fileURLToPath, pathToFileURL } from 'node:url';
5	import { computeVendorSet, SHARED_SUBDIR } from './compute-vendor-set.mjs';
6	
7	// The vendor WRITER (vendoring/DESIGN.md): converge a consumer's .claudinite/shared/
8	// to this canon tree's vendor set and advance the stamp — the local half of the
9	// transactional update. Callers: the adoption flow and an on-demand refresh run
10	// it from a freshly fetched canon tree against the consumer checkout; the
11	// nightly's fleet integration performs the equivalent writes over the API.
12	// Convergence is unconditional and whole-set: shared/ is rebuilt from the set
13	// (stale files vanish, local edits revert), .claudinite/local_packs/ and
14	// everything else in the consumer is untouched. Errors abort BEFORE any write —
15	// the repo keeps running its old snapshot (the transactional contract).
16	//
17	// Convergence is direction-blind (copy-if-different), so a canon checkout behind
18	// main would silently REWIND the member's whole corpus and stamp it newer (#328).
19	// Two guards refuse that before any write, when the canon root carries git
20	// metadata: a passed --ref must equal the checkout's HEAD, and the member's
21	// previously stamped ref must be an ancestor of it. A rootless canon tree
22	// (bootstrap's fetched snapshot — no .git) skips both: it is head by
23	// construction and carries no history to check ancestry against.
24	const canonRoot = dirname(dirname(fileURLToPath(import.meta.url))); // <canon>/vendoring/ — canon-internal, never vendored (#385)
25	
26	// All git use is LOCAL introspection of the canon checkout (rev-parse,
27	// merge-base read the object db — no network, no credential); the remote-head
28	// comparison the guards can't make locally is the worker's, over MCP. Git
29	// discovers .git by walking UP, and a VENDORED copy of this file runs inside
30	// the consumer's own repo (.claudinite/shared/engine/vendoring/) — where git would answer
31	// with the CONSUMER's HEAD — so only a checkout whose toplevel is the canon
32	// root itself speaks for the canon; anything else is treated as rootless.
33	const git = (...args) => execFileSync('git', args, { cwd: canonRoot, stdio: ['ignore', 'pipe', 'ignore'] }).toString().trim();
34	const gitHead = () => {
35	  try {
36	    if (realpathSync(git('rev-parse', '--show-toplevel')) !== realpathSync(canonRoot)) return null;
37	    return git('rev-parse', 'HEAD');
38	  } catch { return null; }
39	};
40	const isAncestorOfHead = (sha) => { try { git('merge-base', '--is-ancestor', sha, 'HEAD'); return true; } catch { return false; } };
41	
42	export async function applyVendor(targetRoot, { ref = null } = {}) {
43	  const settingsPath = join(targetRoot, '.claudinite-checks.json');
44	  if (!existsSync(settingsPath)) {
45	    return { errors: [{ what: `${targetRoot} has no .claudinite-checks.json`, fix: 'write the pack declaration first (adoption seeds it)' }] };
46	  }
47	  let raw;
48	  try {
49	    raw = JSON.parse(readFileSync(settingsPath, 'utf8'));
50	  } catch (e) {
51	    return { errors: [{ what: `.claudinite-checks.json is not valid JSON: ${e.message}`, fix: 'fix the JSON syntax, then rerun' }] };
52	  }
53	  const declared = Array.isArray(raw.packs) ? raw.packs : [];
54	
55	  const head = gitHead();
56	  if (head) {
57	    if (ref && ref !== head) {
58	      return { errors: [{ what: `--ref ${ref} does not match this canon checkout's HEAD (${head})`, fix: 'sync the checkout to the verified remote head (git fetch && git merge --ff-only), then rerun with that head as --ref' }] };
59	    }
60	    ref = ref ?? head; // stamp provenance even when the caller passed none
61	    const prior = raw.claudinite?.ref;
62	    if (prior && !isAncestorOfHead(prior)) {
63	      return { errors: [{ what: `the target's stamped ref (${prior}) is not an ancestor of this checkout's HEAD (${head}) — converging would rewind the member (#328)`, fix: 'sync the canon checkout to the remote head (git fetch && git merge --ff-only; ensure full history), then rerun' }] };
64	    }
65	  }
66	
67	  const { files, errors } = await computeVendorSet(declared);
68	  if (errors.length) return { errors };
69	
70	  const sharedDir = join(targetRoot, SHARED_SUBDIR);
71	  rmSync(sharedDir, { recursive: true, force: true });
72	  for (const file of files) {
73	    const dest = join(sharedDir, file);
74	    mkdirSync(dirname(dest), { recursive: true });
75	    copyFileSync(join(canonRoot, file), dest);
76	  }
77	
78	  // Full ISO datetime, not a bare date: note selection is same-day-INCLUSIVE
79	  // against the stamp's day (a note landing later on the stamp's day must still
80	  // apply — #330), and the datetime pins exactly when this snapshot was taken.
81	  raw.claudinite = { updated: new Date().toISOString(), ...(ref ? { ref } : {}) };
82	  writeFileSync(settingsPath, JSON.stringify(raw, null, 2) + '\n');
83	  return { files: files.length, stamp: raw.claudinite, errors: [] };
84	}
85	
86	// CLI: node <canon>/vendoring/apply-vendor-set.mjs [--target <consumer-root>] [--ref <sha>]
87	if (process.argv[1] && import.meta.url === pathToFileURL(process.argv[1]).href) {
88	  const args = process.argv.slice(2);
89	  const opt = (name) => {
90	    const i = args.indexOf(name);
91	    return i >= 0 ? args[i + 1] : undefined;
92	  };
93	  const result = await applyVendor(opt('--target') ?? process.cwd(), { ref: opt('--ref') ?? null });
94	  if (result.errors.length) {
95	    for (const e of result.errors) console.error(`ERROR: ${e.what}\n  fix: ${e.fix}`);
96	    process.exit(1);
97	  }
98	  console.log(`vendored ${result.files} files into ${SHARED_SUBDIR}; stamp ${JSON.stringify(result.stamp)}`);
99	}
